insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('air-canada-economy', 'air-canada', 'economy', null, 55, 40, 27, 10, 'required', false, 'Soft-sided carrier required in cabin since 1 Jun 2025. Soft max 55x40x27 cm (hard 55x40x23 cm no longer permitted in cabin). Pet + carrier must not exceed 10 kg.', 'https://www.aircanada.com/ca/en/aco/home/plan/special-assistance/pets.html', 'Air Canada — Travelling with pets', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('delta-economy', 'delta', 'economy', null, null, null, null, null, 'recommended', true, 'No guaranteed published maximum; the kennel must fit under the seat, which varies by aircraft. Delta recommends a soft kennel up to 18x11x11 in but confirms exact size by flight. Modelled as incomplete on purpose.', 'https://www.delta.com/us/en/pet-travel/overview', 'Delta — Pet travel overview', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('united-economy', 'united', 'economy', null, 45.7, 27.9, 27.9, null, 'recommended', true, 'Soft carrier max 18x11x11 in (modelled). Hard carrier max 17.5x12x9 in. No published weight limit. Under-seat clearance varies by aircraft.', 'https://www.united.com/en/us/fly/travel/special-needs/pets.html', 'United — Travelling with pets', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('american-economy', 'american', 'economy', null, 48.3, 33, 22.9, null, 'recommended', false, 'Hard kennel max 19x13x9 in (modelled); soft carrier max 18x11x11 in and preferred. Combined weight commonly cited as ~20 lb but AA does not publish a single in-cabin figure, so weight is left unmodeled — confirm with AA.', 'https://www.aa.com/i18n/travel-info/special-assistance/pets.jsp', 'American Airlines — Traveling with pets', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('southwest-economy', 'southwest', 'economy', null, 47, 21.6, 34.3, null, null, false, 'Carrier max 18.5x8.5x13.5 in; hard or soft permitted. Sources differ on the small dimension (8.5 vs 9.5 in) — we use the more conservative 8.5 in. No published weight limit.', 'https://www.southwest.com/help/traveling-with-pets', 'Southwest — Traveling with pets', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('jetblue-economy', 'jetblue', 'economy', null, 43.2, 31.8, 21.6, 9.07, 'recommended', false, 'Carrier max 17x12.5x8.5 in. Both soft and hard carriers are allowed; soft is preferred. Combined pet + carrier max 20 lb.', 'https://www.jetblue.com/traveling-together/traveling-with-pets', 'JetBlue — Traveling with pets', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('alaska-economy', 'alaska', 'economy', null, 43.2, 27.9, 24.1, null, 'recommended', false, 'Soft carrier max 17x11x9.5 in (modelled); hard carrier max 17x11x7.5 in. No published weight limit; hard carriers may not fit under all aircraft seats.', 'https://www.alaskaair.com/content/travel-info/policies/pets-traveling-with-pets', 'Alaska Airlines — Pets traveling with you', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('lufthansa-economy', 'lufthansa', 'economy', null, 55, 40, 23, 8, 'required', false, 'Soft-sided carrier required in cabin. Carrier max 55x40x23 cm. Combined pet + carrier max 8 kg in cabin.', 'https://www.lufthansa.com/de/en/travelling-with-animals', 'Lufthansa — Travelling with animals', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('porter-economy', 'porter', 'economy', null, 55, 40, 23, 9, 'required', false, 'Soft-sided carrier only. Max 55x40x23 cm (22x16x9 in). Combined pet + carrier max 9 kg (20 lb). Must fit under the seat.', 'https://www.flyporter.com/en-ca/travel-information/baggage/pets', 'Porter Airlines — Travelling with pets', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('westjet-economy', 'westjet', 'economy', null, 40.6, 21.6, 25.4, 10, 'required', false, 'Soft-sided carrier required in cabin. Max 16x8.5x10 in (41x21.6x25.4 cm). Combined pet + carrier max 10 kg (22 lb).', 'https://www.westjet.com/en-ca/pets', 'WestJet — Travelling with pets', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('air-transat-economy', 'air-transat', 'economy', null, 43, 24, 25, 8, 'required', false, 'Soft-sided carrier required (hard-sided not permitted in cabin). Max 43x24x25 cm (17x9x10 in). Combined pet + carrier max 8 kg.', 'https://www.airtransat.com/en-CA/forms/pet-information', 'Air Transat — Travelling with pets', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('flair-economy', 'flair', 'economy', null, 41, 23, 25, 10.4, 'required', false, 'Soft-sided carrier required. Max 41x23x25 cm (16x9x10 in). Combined pet + carrier max 10.4 kg (23 lb). In-cabin pets on domestic Canada flights only — not offered on US/international routes.', 'https://www.flyflair.com/travel-info/baggage/pets-onboard', 'Flair Airlines — Pets onboard', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('klm-economy', 'klm', 'economy', null, 46, 28, 24, 8, null, false, 'Economy (all routes) and Business within Europe. Carrier max 46x28x24 cm (18x11x9 in). Combined pet + carrier max 8 kg (17.6 lb). Must fit under the seat. Not allowed in Premium Comfort or Business on intercontinental routes.', 'https://www.klm.com/information/pets/reservation', 'KLM — Flying with your pet in the cabin or hold', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('air-france-economy', 'air-france', 'economy', null, 45.7, 27.9, 27.9, 8, null, true, 'Pet + carrier must weigh less than 8 kg (17.6 lb) for in-cabin travel. Air France does not publish explicit carrier maximum dimensions — the values below (~18x11x11 in) are from third-party sources and need re-verification against official Air France policy. Confirm directly with Air France before travel.', 'https://wwws.airfrance.fr/en/information/passagers/voyager-avec-son-animal-chien-chat', 'Air France — Travel with your pet', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('frontier-economy', 'frontier', 'economy', null, 45.7, 35.6, 27.9, null, 'recommended', false, 'Hard-sided max 18x14x8 in; soft-sided max 18x14x11 in. Soft-sided recommended. No published weight limit. Domestic US flights only — no cargo hold pets. Only service dogs accepted on international flights.', 'https://faq.flyfrontier.com/help/do-you-allow-pets-on-the-plane', 'Frontier Airlines — Pets Onboard', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('spirit-economy', 'spirit', 'economy', null, 45.7, 35.6, 22.9, 18.14, 'required', false, 'Soft-sided carrier required (hard-sided not permitted). Max 18x14x9 in. Combined pet + carrier max 40 lb (18.1 kg). Domestic US only. Spirit is strict on carrier dimensions — carrier must slide completely under the seat.', 'https://www.spirit.com/en/us/pets', 'Spirit Airlines — Pets', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('avelo-economy', 'avelo', 'economy', null, 43.2, 22.9, 33, null, null, false, 'Hard-sided max 17x13x9 in (43x33x22 cm); soft-sided must fit in the same space. Both hard and soft permitted. No published weight limit. Domestic US only. Up to 8 pet carriers per flight.', 'https://www.aveloair.com/help/pet-policy', 'Avelo Airlines — Pet Policy', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('british-airways-cargo-only', 'british-airways', 'economy', null, null, null, null, null, null, false, 'British Airways does NOT allow pets in the cabin on any route (except assistance/service dogs). All pets must travel in the hold via cargo. This airline is listed so users get an honest answer instead of ''unsupported airline''. Confirm arrangements with PetAir UK (export) or IAG Cargo (import).', 'https://www.britishairways.com/content/information/travel-assistance/travelling-with-pets', 'British Airways — Travelling with pets', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('allegiant-economy', 'allegiant', 'economy', null, 48.3, 40.6, 22.9, null, 'recommended', false, 'Soft-sided carrier recommended. Max 19x16x9 in (48x41x23 cm). Combined pet + carrier max 20 lb (9 kg) per carrier (up to 2 carriers per booking). In-cabin only — no cargo hold pets. Domestic US (contiguous 48 states) and Puerto Rico only. Up to 2 pets per carrier, 2 carriers per booking.', 'https://www.allegiantair.com/traveling-with-pets', 'Allegiant Air — Traveling with Pets', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('hawaiian-economy', 'hawaiian', 'economy', null, 43.2, 27.9, 24.1, 11.34, 'required', false, 'Soft-sided carrier required in cabin. Max 17x11x9.5 in (43x28x24 cm). Combined pet + carrier max 25 lb (11.3 kg). Allowed on Hawaii-mainland and interisland routes. $35 interisland, $125 mainland-Hawaii. Pets not accepted in cabin on international flights.', 'https://www.hawaiianairlines.com/content/travel-info/pets', 'Hawaiian Airlines — Traveling with Pets', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('emirates-cargo-only', 'emirates', 'economy', null, null, null, null, null, null, false, 'Emirates does NOT allow pets in the cabin (except falcons on select Dubai-Pakistan routes and certified guide dogs/assistance animals). All other pets must travel as manifest cargo via Emirates SkyCargo. This airline is listed so users get an honest answer instead of ''unsupported airline''.', 'https://www.emirates.com/english/help/faq/449416/can-i-carry-live-animals-on-emirates-flights', 'Emirates — Can I carry live animals on Emirates flights?', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('ryanair-no-pets', 'ryanair', 'economy', null, null, null, null, null, null, false, 'Ryanair does NOT carry animals on board any flights (except certified guide/assistance dogs on certain routes). Pets cannot travel in the cabin or cargo hold. This airline is listed so users get an honest answer instead of ''unsupported airline''.', 'https://help.ryanair.com/hc/en-gb/articles/12890968181521-Does-Ryanair-carry-animals', 'Ryanair — Does Ryanair carry animals?', 'airline_official', '2026-06-18') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('air-canada-first', 'air-canada', 'first', null, 55, 40, 27, 10, 'required', false, 'Soft-sided carrier required in cabin since 1 Jun 2025. Soft max 55x40x27 cm (hard 55x40x23 cm no longer permitted in cabin). Pet + carrier must not exceed 10 kg. Unverified cabin-specific fallback: no separate first class in-cabin carrier rule found; copied from Economy as a conservative stand-in.', 'https://www.aircanada.com/ca/en/aco/home/plan/special-assistance/pets.html', 'Air Canada — Travelling with pets (First Class fallback)', 'airline_official', '2026-05-26') on conflict (id) do nothing;
insert into public.airline_rules (id, airline_id, cabin, aircraft_type, max_length_cm, max_width_cm, max_height_cm, max_combined_weight_kg, soft_sided_requirement, aircraft_varies, notes, source_url, source_label, source_type, last_verified_at) values ('united-premium-economy', 'united', 'premium_economy', null, 45.7, 27.9, 27.9, null, 'recommended', true, 'Soft carrier max 18x11x11 in (modelled). Hard carrier max 17.5x12x9 in. No published weight limit. Under-seat clearance varies by aircraft. Unverified cabin-specific fallback: no separate premium economy in-cabin carrier rule found; copied from Economy as a conservative stand-in.', 'https://www.united.com/en/us/fly/travel/special-needs/pets.html', 'United — Travelling with pets (Premium Economy fallback)', 'airline_official', '2026-05-26') on conflict (id) do nothing;
